import{_ as a,o as t,c as i,ak as l}from"./chunks/framework.C5oxOlRz.js";const k=JSON.parse('{"title":"Freestyle 项目","description":"","frontmatter":{"version":"2.1.8"},"headers":[],"relativePath":"guide/feature/wechat-work/freestyle.md","filePath":"guide/feature/wechat-work/freestyle.md","lastUpdated":1780022608000}'),o={name:"guide/feature/wechat-work/freestyle.md"};function r(d,e,s,c,n,h){return t(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="freestyle-项目" tabindex="-1">Freestyle 项目 <a class="header-anchor" href="#freestyle-项目" aria-label="Permalink to “Freestyle 项目”">​</a></h1><p>以下示例适用于 <code>Freestyle</code> 任务中通过插件界面配置企业微信机器人通知的场景。</p><h2 id="_1-机器人配置" tabindex="-1">1. 机器人配置 <a class="header-anchor" href="#_1-机器人配置" aria-label="Permalink to “1. 机器人配置”">​</a></h2><p>在全局配置中添加企业微信机器人后，可在 Freestyle 任务中选择对应机器人。</p><p>企业微信机器人推荐直接填写群机器人 <code>key</code>，插件会自动拼接为：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>https://qyapi.weixin.qq.com/cgi-bin/webhook/send?key={key}</span></span></code></pre></div><p>如果你已经拿到完整 Webhook，也可以切换到 <code>自定义</code> 模式直接粘贴。</p><h2 id="_2-默认卡片模式" tabindex="-1">2. 默认卡片模式 <a class="header-anchor" href="#_2-默认卡片模式" aria-label="Permalink to “2. 默认卡片模式”">​</a></h2><p>Freestyle 任务默认使用插件内置的构建摘要卡片。企业微信平台会将其渲染为 <code>template_card.news_notice</code> 模板卡片，自动展示：</p><ul><li>项目名称和项目链接</li><li>构建编号和构建链接</li><li>构建状态</li><li>构建耗时</li><li>执行人</li><li>最多 3 个跳转按钮</li></ul><p>如果未手动配置按钮，插件会默认生成 <code>更改记录</code> 和 <code>控制台</code> 两个跳转按钮。</p><h2 id="_3-自定义消息模式建议" tabindex="-1">3. 自定义消息模式建议 <a class="header-anchor" href="#_3-自定义消息模式建议" aria-label="Permalink to “3. 自定义消息模式建议”">​</a></h2><p>企业微信 <code>Freestyle</code> 任务当前更推荐使用默认卡片模式。</p><p>原因是企业微信平台的消息能力和飞书 / Lark 不同，<code>Freestyle</code> 下的 <code>自定义消息</code> 体验也不等同于飞书那种“原始 Markdown / JSON 卡片编辑器”。如果你需要精确控制正文结构、按钮、图片或提醒对象，优先使用 <code>Pipeline</code> 中的 <code>wechatWork</code> 步骤。</p><h2 id="_4-使用建议" tabindex="-1">4. 使用建议 <a class="header-anchor" href="#_4-使用建议" aria-label="Permalink to “4. 使用建议”">​</a></h2><ul><li>需要 <code>@</code> 提醒时，优先在任务配置里填写用户 ID 或手机号，交给插件统一处理。</li><li>需要卡片图片时，请使用公网或 Jenkins 所在网络可直接访问的 <code>http/https</code> 图片地址。</li><li>如果你需要发送特别复杂的卡片布局，企业微信平台能力有限，建议改用 <code>Pipeline</code> 的 <code>wechatWork</code> 步骤，或迁移到飞书 / Lark 机器人。</li></ul>',16)])])}const _=a(o,[["render",r]]);export{k as __pageData,_ as default};
